def as_dict_list(limit: int = 50) -> list[dict[str, str]]:
    out: list[dict[str, str]] = []
    for idx, it in enumerate(iter_items()):
        if idx >= limit:
            break
        out.append({'code': it.code, 'title': it.title, 'desc': it.desc, 'created_at': it.created_at})
    return out

